(async () => {
  const { data: test, error: testError } = await sb
    .from('diagnostic_tests')
    .insert({
      slug: 'ap-chem-readiness',
      title: 'AP Chemistry Readiness Diagnostic',
      description: 'A free diagnostic for students moving from Honors or Regular Chemistry into AP Chemistry. Answer 90 multiple-choice questions covering the foundational skills AP Chem assumes you already have, then get an instant, topic-by-topic breakdown of your strengths and weaknesses plus a personalized study plan before the course begins.',
      question_count_per_attempt: 90,
      duration_minutes: 120,
    })
    .select('id')
    .single();
  if (testError) throw testError;
  console.log('Created test:', test.id);

  const topicIds = [];
  for (const t of TOPICS) {
    const { data, error } = await sb.from('diagnostic_topics').insert({
      diagnostic_test_id: test.id,
      title: t.title,
      prep_advice: t.prep_advice,
    }).select('id').single();
    if (error) throw error;
    topicIds.push(data.id);
  }
  console.log('Created', topicIds.length, 'topics');

  const rows = QUESTIONS.map(q => ({
    diagnostic_test_id: test.id,
    topic_id: topicIds[q.topic],
    content: q.content,
    mcq_options: q.options,
    mcq_correct_index: q.correct,
    source: q.source,
  }));

  for (let i = 0; i < rows.length; i += 100) {
    const chunk = rows.slice(i, i + 100);
    const { error: qError } = await sb.from('diagnostic_questions').insert(chunk);
    if (qError) throw qError;
  }
  console.log('Inserted', rows.length, 'questions');
  console.log('Visit: /diagnostic/ap-chem-readiness');
})();
